// // This module implements a 8-bit register that loads data on the falling edge of the clock when the load signal is low.
module register(
    input wire clk,
    input wire load,
    input wire [7:0] d,
    output reg [7:0] q
);

always @(posedge clk) begin
    if (load) begin
        q <= d;
    end
end

endmodule
